#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int tc = 0; tc < T; ++tc) {
        int days[12];
        for (int i = 0; i < 12; ++i) {
            scanf("%d", &days[i]);
        }
        for (int i = 0; i < 12; ++i) {
            printf("%d\n", days[i]);
            if (days[i] < 30) break;
        }
    }
    return 0;
}

